io.ReadFull Behavior:
go
// NOT this (unreliable):
n, _ := reader.Read(buf)  // May return n < 4
// THIS (correct):
_, err := io.ReadFull(reader, lengthBuf)
// Guarantees exactly 4 bytes or error

Decode Length (Big-Endian)
go
length := binary.BigEndian.Uint32(lengthBuf)
// length = 16
// Validate:
if length > MaxFrameSize {
return ErrFrameTooLarge
}
if length == 0 {
return ErrInvalidLength
}

Completion Check:
go
// io.ReadFull guarantees:
// n == len(payload) OR error
// At this point:
// - lengthBuf contains 4 bytes
// - payload contains 16 bytes
// - Ready to parse command

Function Return
go
return payload, nil
// payload = complete 16-byte frame
// Ready for ParseCommand(payload)
